tests:
def test_chain():
    result = Stream(range(10)).filter(lambda x: x%2==0).map(lambda x: x*10).to_list()
    assert result == [0, 20, 40, 60, 80]

def test_lazy_take_infinite_safe():
    def naturals():
        n = 0
        while True:
            yield n
            n += 1
    assert Stream(naturals()).take(5).to_list() == [0,1,2,3,4]

def test_complex_chain():
    result = Stream(range(20)).filter(lambda x: x%2==0).map(lambda x: x*x).take(3).to_list()
    assert result == [0, 4, 16]
